def render_teams_message(report: RunReport) -> dict[str, Any]:
    """The full Teams webhook payload for ``report`` (message + adaptive card)."""
    return {
        "type": "message",
        "attachments": [
            {"contentType": _CARD_CONTENT_TYPE, "content": _adaptive_card(report)},
