    block: dict[str, Any] = {"type": "TextBlock", "text": text}
    if props.pop("wrap", False):
        block["wrap"] = True
    if props.pop("is_subtle", False):
        block["isSubtle"] = True
    for key in ("weight", "size", "color", "spacing"):
        if key in props:
            block[key] = props[key]
    return block

